import posts from "@/data/posts.json";

export const Home = () => {
  return (
    <main style={{ fontFamily: "sans-serif", maxWidth: "800px", margin: "0 auto", padding: "2rem" }}>
      <h1>Blog</h1>
      <div>
        {posts.map((post) => (
          <article
            key={post.slug}
            style={{
              border: "1px solid #ddd",
              borderRadius: "8px",
              padding: "1.5rem",
              marginBottom: "1.5rem",
            }}
          >
            <h2 style={{ margin: "0 0 0.5rem" }}>
              <a href={`/posts/${post.slug}`} style={{ textDecoration: "none", color: "#0070f3" }}>
                {post.title}
              </a>
            </h2>
            <p style={{ margin: "0", color: "#666", fontSize: "0.9rem" }}>
              By {post.author} &middot; {post.publishedAt}
            </p>
          </article>
        ))}
      </div>
    </main>
  );
};

import { marked } from "marked";
import posts from "@/data/posts.json";
import type { RequestInfo } from "rwsdk/worker";

function htmlEscape(str: string): string {
  return str
    .replace(/&/g, "&amp;")
    .replace(/"/g, "&quot;")
    .replace(/'/g, "&#39;")
    .replace(/</g, "&lt;")
    .replace(/>/g, "&gt;");
}

export async function postDetailHandler({ params }: RequestInfo<{ slug: string }>) {
  const post = posts.find((p) => p.slug === params.slug);

  if (!post) {
    return new Response("Not Found", { status: 404 });
  }

  const bodyHtml = await marked(post.body);
  const metaDesc = htmlEscape(post.body.slice(0, 100));
  const escapedTitle = htmlEscape(post.title);

  const html = `<!DOCTYPE html>
<html lang="en">
<head>
  <meta charset="utf-8" />
  <meta name="viewport" content="width=device-width, initial-scale=1" />
  <meta name="description" content="${metaDesc}" />
  <title>${escapedTitle}</title>
</head>
<body style="font-family: sans-serif; max-width: 800px; margin: 0 auto; padding: 2rem;">
  <p><a href="/">&larr; Back to all posts</a></p>
  <h1>${escapedTitle}</h1>
  <p style="color: #666; font-size: 0.9rem;">By ${htmlEscape(post.author)} &middot; ${htmlEscape(post.publishedAt)}</p>
  <hr />
  ${bodyHtml}
</body>
</html>`;

  return new Response(html, {
    status: 200,
    headers: { "Content-Type": "text/html; charset=utf-8" },
  });
}

export function postRawHandler({ params }: RequestInfo<{ slug: string }>) {
  const post = posts.find((p) => p.slug === params.slug);

  if (!post) {
    return new Response("Not Found", { status: 404 });
  }

  return new Response(post.body, {
    status: 200,
    headers: { "Content-Type": "text/plain; charset=utf-8" },
  });
}

import { render, route } from "rwsdk/router";
import { defineApp } from "rwsdk/worker";

import { Document } from "@/app/document";
import { setCommonHeaders } from "@/app/headers";
import { Home } from "@/app/pages/home";
import { postDetailHandler, postRawHandler } from "@/app/pages/post";

export type AppContext = {};

export default defineApp([
  setCommonHeaders(),
  ({ ctx }) => {
    // setup ctx here
    ctx;
  },
  route("/posts/:slug/raw", postRawHandler),
  route("/posts/:slug", postDetailHandler),
  render(Document, [route("/", Home)]),
]);

